import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';
import { optionLabelByValue, useParcelOptions } from 'features/shared/selectOptionHelpers';

export function CutsPage() {
  const parcelOptions = useParcelOptions();

  return (
    <CrudResourceModule
      title="Cortes Vigentes"
      path={API_PATHS.cuts}
      columns={[
        { key: 'parcela', label: 'Parcela', render: (row) => optionLabelByValue(parcelOptions, row.parcela) },
        { key: 'tipo_corte', label: 'Tipo corte' },
        { key: 'estado', label: 'Estado' },
        { key: 'fecha', label: 'Fecha' },
        {
          key: 'activo',
          label: 'Vigente',
          render: (row) => <Chip size="small" label={row.activo ? 'Sí' : 'No'} color={row.activo ? 'success' : 'default'} />
        }
      ]}
      fields={[
        { name: 'parcela', label: 'Parcela', type: 'select', required: true, options: parcelOptions },
        {
          name: 'tipo_corte',
          label: 'Tipo corte',
          type: 'select',
          required: true,
          options: [
            { value: 'AYS', label: 'Agua y servicios' },
            { value: 'AGUA', label: 'Agua' },
            { value: 'LUZ', label: 'Luz' }
          ]
        },
        { name: 'estado', label: 'Estado' },
        { name: 'fecha', label: 'Fecha', type: 'date' },
        { name: 'motivo', label: 'Motivo', fullWidth: true },
        { name: 'sello', label: 'Sello' },
        { name: 'activo', label: 'Vigente', type: 'checkbox', defaultValue: true },
        { name: 'observaciones', label: 'Observaciones', type: 'textarea', fullWidth: true }
      ]}
      defaultOrdering="-fecha"
    />
  );
}

export function ServiceHistoryPage() {
  const parcelOptions = useParcelOptions();

  return (
    <CrudResourceModule
      title="Histórico de Servicios"
      path={API_PATHS.serviceHistory}
      columns={[
        { key: 'parcela', label: 'Parcela', render: (row) => optionLabelByValue(parcelOptions, row.parcela) },
        { key: 'numero_orden', label: 'N° Orden' },
        { key: 'solicitante', label: 'Solicitante' },
        { key: 'resultado', label: 'Resultado' },
        { key: 'fecha_ingreso', label: 'Fecha ingreso' }
      ]}
      fields={[
        { name: 'parcela', label: 'Parcela', type: 'select', required: true, options: parcelOptions },
        { name: 'numero_orden', label: 'N° Orden' },
        { name: 'solicitante', label: 'Solicitante' },
        { name: 'resultado', label: 'Resultado' },
        { name: 'descripcion', label: 'Descripción', type: 'textarea', fullWidth: true },
        { name: 'fecha_ingreso', label: 'Fecha ingreso', type: 'date' },
        { name: 'fecha_ejecucion', label: 'Fecha ejecución', type: 'date' },
        { name: 'ejecutante', label: 'Ejecutante' },
        { name: 'lugar_corte_reposicion', label: 'Lugar corte/reposición', fullWidth: true },
        { name: 'observaciones', label: 'Observaciones', type: 'textarea', fullWidth: true }
      ]}
      defaultOrdering="-fecha_ingreso"
    />
  );
}
